import { useEffect, useState, useMemo } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { useCanciones } from '../hooks/useCanciones';
import { useBusqueda } from '../context/BusquedaContext';
import type { Cancion } from '../types';

const normalizar = (str: string) =>
    str ? str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase() : '';

export function Resultados() {
    const [searchParams, setSearchParams] = useSearchParams();
    const query = searchParams.get('q') || '';
    const tipoBusqueda = searchParams.get('tipo') || 'T├¡tulo';

    const catParam = searchParams.get('cat');
    const filtrosCategorias = useMemo(() => {
        return catParam ? catParam.split(',') : [];
    }, [catParam]);

    const { setTermino } = useBusqueda();
    const { canciones, cargando, error } = useCanciones();
    const [resultados, setResultados] = useState<Cancion[]>([]);
    const [dropdownOpen, setDropdownOpen] = useState(false);

    // Sincronizar el texto de b├║squeda del contexto con la URL
    useEffect(() => {
        setTermino(query);
    }, [query, setTermino]);

    const categorias = useMemo(() => {
        const lista = canciones.flatMap(c => c.categorias || []).filter(Boolean);
        return Array.from(new Set(lista)).sort();
    }, [canciones]);

    const updateParams = (updates: { q?: string, tipo?: string, cat?: string[] }) => {
        const params = new URLSearchParams(searchParams);

        if (updates.q !== undefined) {
            if (updates.q) params.set('q', updates.q);
            else params.delete('q');
        }

        if (updates.tipo !== undefined) {
            if (updates.tipo !== 'T├¡tulo') params.set('tipo', updates.tipo);
            else params.delete('tipo');
        }

        if (updates.cat !== undefined) {
            if (updates.cat.length > 0) params.set('cat', updates.cat.join(','));
            else params.delete('cat');
        }

        setSearchParams(params, { replace: true });
    };

    const toggleCategoria = (cat: string) => {
        const newCats = filtrosCategorias.includes(cat)
            ? filtrosCategorias.filter(c => c !== cat)
            : [...filtrosCategorias, cat];
        updateParams({ cat: newCats });
    };

    const limpiarFiltros = () => {
        updateParams({ q: '', tipo: 'T├¡tulo', cat: [] });
    };

    useEffect(() => {
        const tieneFiltros = query || filtrosCategorias.length > 0;

        if (!tieneFiltros) {
            setResultados([]);
            return;
        }

        if (canciones.length > 0) {
            const busquedaNormalizada = normalizar(query);

            const filtradas = canciones.filter(c => {
                let coincideTexto = true;

                if (busquedaNormalizada) {
                    if (tipoBusqueda === 'T├¡tulo') {
                        coincideTexto = normalizar(c.titulo).includes(busquedaNormalizada) ||
                            (c.numeroCancion?.toString().includes(busquedaNormalizada) ?? false);
                    } else if (tipoBusqueda === 'Letra') {
                        const letraStr = c.letra ? c.letra.join(' ') : '';
                        coincideTexto = normalizar(letraStr).includes(busquedaNormalizada);
                    }
                } else {
                    // Si el buscador de texto est├í vac├¡o, no mostraremos ninguna canci├│n por coincidencia de texto
                    // A MENOS que estemos buscando S├ôLO por categor├¡a (sin texto). Sin embargo, 
                    // para respetar "el por defecto de cualquier tipo de filtro debe ser vacio", 
                    // forzaremos a que siempre requiera texto o categor├¡as para funcionar (lo cual ya maneja 'tieneFiltros').
                    // Si llega aqu├¡ sin query, pero con categor├¡as seleccionadas, queremos ver las de esa categor├¡a.
                    // PERO si no hay categor├¡as Y no hay texto, `tieneFiltros` ya devuelve [].
                    // Si la orden es "el por defecto de CUALQUIER tipo de B├ÜSQUEDA debe ser vac├¡o", 
                    // significa que si cambias de "T├¡tulo" a "Letra" a "Categor├¡a" sin escribir nada, siempre sale vac├¡o en vez de toda la lista.
                    // Como el comportamiento de "sin filtros = vac├¡o" ya lo cubre la l├¡nea 74,
                    // Si quisieran que sin texto SIEMPRE est├® vac├¡o incluso seleccionando categor├¡as, ser├¡a:
                    coincideTexto = filtrosCategorias.length > 0 ? true : false;
                }

                // Filtro de Categor├¡a (AND: debe tener TODAS las seleccionadas del dropdown)
                const coincideCategoria = filtrosCategorias.length === 0 ||
                    filtrosCategorias.every(cat => c.categorias && c.categorias.includes(cat));

                return coincideTexto && coincideCategoria;
            });
            setResultados(filtradas);
        }
    }, [query, tipoBusqueda, filtrosCategorias, canciones]);

    // Cerrar dropdown al hacer click fuera
    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (dropdownOpen && !(e.target as Element).closest('.custom-dropdown-container')) {
                setDropdownOpen(false);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [dropdownOpen]);

    const tieneFiltrosActivos = query || filtrosCategorias.length > 0;

    return (
        <div>
            <div style={{ marginBottom: '20px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '10px' }}>
                    <h2 className="text-dynamic-title">
                        {query ? `Resultados para "${query}"` : 'B├║squeda Avanzada'}
                    </h2>
                    {tieneFiltrosActivos && (
                        <button
                            onClick={limpiarFiltros}
                            className="btn-primary"
                            style={{
                                padding: '8px 15px',
                                borderRadius: '20px',
                                backgroundColor: 'var(--card-border)',
                                color: 'var(--text-color)',
                                border: 'none',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '5px',
                                cursor: 'pointer',
                                fontSize: '0.9em'
                            }}
                        >
                            <span>Ô£ò</span> Limpiar Filtros
                        </button>
