import { useState, useEffect } from 'react';
import type { Cancion } from '../types';

export function useCanciones() {
    const [canciones, setCanciones] = useState<Cancion[]>([]);
    const [cargando, setCargando] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);

    const API_URL = import.meta.env.VITE_API_URL;

    useEffect(() => {
        if (!API_URL) {
            console.error("VITE_API_URL no est├í definido");
            setError("Error de configuraci├│n: API_URL no definida");
            setCargando(false);
            return;
        }

        fetch(API_URL)
            .then(res => {
                if (!res.ok) {
                    throw new Error(`Error en la petici├│n: ${res.statusText}`);
                }
                return res.json();
            })
            .then((data: Cancion[]) => {
                setCanciones(data);
                setCargando(false);
            })
            .catch(err => {
                console.error(err);
                setError(err.message || "Error al cargar canciones");
                setCargando(false);
            });
    }, [API_URL]);

    return { canciones, cargando, error };
}

export interface ChordSegment {
    chord: string | null;
    text: string;
}

export function parseLyricsLine(line: string): ChordSegment[] {
    const segments: ChordSegment[] = [];

    // Regex para encontrar acordes entre corchetes: [LAm]texto
    // Captura el acorde y luego el texto hasta el siguiente acorde o fin de linea
    const regex = /\[(.*?)\]([^\[]*)/g;

    let match;

    // Si la linea no arranca con acorde, capturamos el texto inicial
    const firstBracketIndex = line.indexOf('[');
    if (firstBracketIndex > 0) {
        segments.push({
            chord: null,
            text: line.substring(0, firstBracketIndex)
        });
    } else if (firstBracketIndex === -1) {
        // Sin acordes en toda la linea
        return [{ chord: null, text: line }];
    }

    while ((match = regex.exec(line)) !== null) {
        // match[1] es el acorde (sin corchetes)
        // match[2] es el texto que le sigue
        segments.push({
            chord: match[1],
            text: match[2]
        });
    }

    // Agregar un espacio en blanco entre acordes consecutivos para correcta separaci├│n visual
    for (let i = 0; i < segments.length - 1; i++) {
        if (segments[i].chord !== null && segments[i].text === '' && segments[i + 1].chord !== null) {
            segments[i].text = ' ';
        }
    }

    return segments;
}

// Escala crom├ítica usando solo sostenidos (#)
export const SCALE = [
    'DO', 'DO#', 'RE', 'RE#', 'MI', 'FA', 'FA#', 'SOL', 'SOL#', 'LA', 'LA#', 'SI'
];

/**
 * Obtiene la distancia en semitonos desde una nota origen a una destino.
 * @param fromKey Nota original (ej: "DO")
 * @param toKey Nota destino (ej: "RE")
 * @returns Diferencia en semitonos
 */
export function getKeyDistance(fromKey: string, toKey: string): number {
    // Normalizar quitando sufijos ("LAm" -> "LA")
    // Usamos la misma l├│gica de "root" que transposeChord
    const sortedScale = [...SCALE].sort((a, b) => b.length - a.length);
    const getRoot = (k: string) => sortedScale.find(note => k.toUpperCase().startsWith(note)) || k;

    const fromRoot = getRoot(fromKey);
    const toRoot = getRoot(toKey);

    const fromIndex = SCALE.indexOf(fromRoot);
    const toIndex = SCALE.indexOf(toRoot);

    if (fromIndex === -1 || toIndex === -1) return 0;

    let diff = toIndex - fromIndex;
    // Ajuste para el camino m├ís corto? 
    // Por ahora simple resta. Si estoy en DO (0) y voy a SI (11), diff = 11.
    // Si estoy en SI (11) y voy a DO (0), diff = -11.
    return diff;
}

/**
 * Transpone una nota musical (ej: "LAm", "DO#7") por un n├║mero de semitonos.
 * Permite que el acorde contenga texto adicional como "Intro: DO" y transpondr├í solo el acorde v├ílido.
 * @param chordText La nota, acorde o texto a transponer.
 * @param semitones Cantidad de semitonos a mover (puede ser negativo).
 */
export function transposeChord(chordText: string, semitones: number): string {
    if (semitones === 0) return chordText;

    // Buscamos cualquier palabra que empiece con una nota v├ílida
    // \b asegura que empezamos en un l├¡mite de palabra
    const regex = /\b(DO|RE|MI|FA|SOL|LA|SI)(#?)([a-zA-Z0-9#\+\-┬║├©]*)(?:\/(DO|RE|MI|FA|SOL|LA|SI)(#?))?(?=\s|$|[^\w#\+\-┬║├©/])/g;

    return chordText.replace(regex, (match, root1, sharp1, suffix, root2, sharp2) => {
        const lowerSuffix = suffix.toLowerCase();
        const validSuffixRegex = /^(m|sus\d*|dim|aug|maj\d*|add\d*|min|[\d\+\-┬║├©b#])*$/;

        // Excepci├│n expl├¡cita para la palabra "SOLO"
        if (match === 'SOLO') return match;

        // Si el sufijo tiene caracteres que no son t├¡picos de acordes (y no es 'M' para mayor)
        if (suffix && !validSuffixRegex.test(lowerSuffix) && suffix !== 'M') {
            return match;
        }

        const transposeNote = (root: string, sharp: string) => {
            const note = root + (sharp || '');
            const index = SCALE.indexOf(note);
            if (index === -1) return note;

            let newIndex = (index + semitones) % SCALE.length;
            if (newIndex < 0) newIndex += SCALE.length;
            return SCALE[newIndex];
        };

        let result = transposeNote(root1, sharp1) + suffix;
        if (root2) {
            result += '/' + transposeNote(root2, sharp2);
        }

        return result;
    });
}
